import{_ as e,c as o,o as t,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"快速开始: 上手 Plannotator | plannotator","description":"学习 Plannotator 的快速开始方法。在 5 分钟内了解核心功能，完成 Claude Code 或 OpenCode 插件安装配置。","frontmatter":{"title":"快速开始: 上手 Plannotator | plannotator","sidebarTitle":"5 分钟快速上手","subtitle":"快速开始: 上手 Plannotator","description":"学习 Plannotator 的快速开始方法。在 5 分钟内了解核心功能，完成 Claude Code 或 OpenCode 插件安装配置。","order":1},"headers":[],"relativePath":"zh/backnotprop/plannotator/start/index.md","filePath":"zh/backnotprop/plannotator/start/index.md"}'),l={name:"zh/backnotprop/plannotator/start/index.md"};function r(d,a,i,s,c,p){return t(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>本章节帮助你从零开始使用 Plannotator。你将了解 Plannotator 是什么、它能解决什么问题，并在你使用的 AI Coding Agent（Claude Code 或 OpenCode）中完成安装配置。</p><h2 id="本章内容" tabindex="-1">本章内容 <a class="header-anchor" href="#本章内容" aria-label="Permalink to &quot;本章内容&quot;">​</a></h2><div class="grid-cards"><h3 id="快速开始-1" tabindex="-1"><a href="./getting-started/">快速开始</a> <a class="header-anchor" href="#快速开始-1" aria-label="Permalink to &quot;[快速开始](./getting-started/)&quot;">​</a></h3><p>了解 Plannotator 的核心功能和使用场景，在 5 分钟内完成首次体验。适合所有新用户作为入门第一课。</p><h3 id="安装-claude-code-插件" tabindex="-1"><a href="./installation-claude-code/">安装 Claude Code 插件</a> <a class="header-anchor" href="#安装-claude-code-插件" aria-label="Permalink to &quot;[安装 Claude Code 插件](./installation-claude-code/)&quot;">​</a></h3><p>在 Claude Code 中安装并配置 Plannotator 插件，支持插件系统和手动 Hook 两种方式，涵盖本地和远程环境配置。</p><h3 id="安装-opencode-插件" tabindex="-1"><a href="./installation-opencode/">安装 OpenCode 插件</a> <a class="header-anchor" href="#安装-opencode-插件" aria-label="Permalink to &quot;[安装 OpenCode 插件](./installation-opencode/)&quot;">​</a></h3><p>在 OpenCode 中安装并配置 Plannotator 插件，启用 <code>submit_plan</code> tool 和 <code>/plannotator-review</code> 命令。</p></div><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">推荐顺序</p><ol><li><strong>先读 <a href="./getting-started/">快速开始</a></strong>：了解 Plannotator 是什么、能做什么，建立整体认知</li><li><strong>再选一个安装教程</strong>：根据你使用的 AI Coding Agent 选择对应的安装指南 <ul><li>使用 Claude Code → <a href="./installation-claude-code/">安装 Claude Code 插件</a></li><li>使用 OpenCode → <a href="./installation-opencode/">安装 OpenCode 插件</a></li></ul></li></ol></div><p>完成安装后，你就可以开始使用 Plannotator 进行计划评审和代码评审了。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章节后，继续学习 <strong><a href="./../platforms/">平台功能</a></strong>，掌握计划评审和代码评审的完整用法：</p><ul><li>计划评审基础：批准、拒绝、添加注释</li><li>图像标注：在计划中附加截图并标注</li><li>代码评审：可视化 Git diff，添加行级注释</li></ul>',10)])])}const C=e(l,[["render",r]]);export{u as __pageData,C as default};
